bash -lc python3 - <<'PY'
import os, json
procs=[]
for d in os.listdir('/proc'):
    if not d.isdigit():
        continue
    pid=int(d)
    try:
        cmd=open(f'/proc/{pid}/cmdline','rb').read().decode('utf-8','ignore').replace('\x00',' ').strip()
    except Exception:
        continue
    if 'server.py' in cmd:
        try:
            cwd=os.readlink(f'/proc/{pid}/cwd')
        except Exception:
            cwd='?'
        procs.append({'pid':pid,'cmd':cmd,'cwd':cwd})
print(json.dumps(procs, ensure_ascii=False))
